"""Brand theme helpers for Streamlit and Plotly."""

import plotly.io as pio
import streamlit as st

# Brand palette from docs/manual-identidad-gretercomunica.md
GARNET = "#6B1E3A"
GARNET_DEEP = "#4A1228"
GOLD = "#C9A96E"
GOLD_LIGHT = "#E2C99A"
CREAM = "#FAF6EF"
BLUSH = "#F0DDD6"
BLUSH_MID = "#E8C9BE"
CHARCOAL = "#2C1A20"
WARM_GRAY = "#8A7A7F"


def apply_plotly_theme() -> None:
    """Apply a global Plotly theme aligned with brand colors."""
    pio.templates["greter"] = {
        "layout": {
            "paper_bgcolor": CREAM,
            "plot_bgcolor": CREAM,
            "font": {"family": "Jost, sans-serif", "color": CHARCOAL, "size": 14},
            "title": {"font": {"family": "Playfair Display, serif", "size": 24, "color": GARNET_DEEP}},
            "colorway": [GARNET, GOLD, GARNET_DEEP, BLUSH_MID, GOLD_LIGHT, WARM_GRAY],
            "xaxis": {"gridcolor": BLUSH_MID, "zerolinecolor": BLUSH_MID},
            "yaxis": {"gridcolor": BLUSH_MID, "zerolinecolor": BLUSH_MID},
        }
    }
    pio.templates.default = "greter"


def apply_streamlit_theme() -> None:
    """Inject global CSS to enforce brand typography and accents."""
    st.markdown(
        """
        <style>
        @import url('https://fonts.googleapis.com/css2?family=Jost:wght@300;400;500;600&family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400;1,600&display=swap');

        :root {
            --greter-garnet: #6B1E3A;
            --greter-garnet-deep: #4A1228;
            --greter-gold: #C9A96E;
            --greter-gold-light: #E2C99A;
            --greter-cream: #FAF6EF;
            --greter-blush: #F0DDD6;
            --greter-blush-mid: #E8C9BE;
            --greter-charcoal: #2C1A20;
            --greter-warm-gray: #8A7A7F;
        }

        html, body, [class*="css"], [data-testid="stAppViewContainer"], [data-testid="stApp"],
        [data-testid="stHeader"], [data-testid="stToolbar"], .main, .block-container {
            font-family: 'Jost', sans-serif;
            color: var(--greter-charcoal);
            background-color: var(--greter-cream);
        }

        h1, h2, h3, h4, h5, h6 {
            font-family: 'Playfair Display', serif !important;
            color: var(--greter-garnet-deep);
            letter-spacing: 0.01em;
        }

        p, li, label, span, div {
            font-family: 'Jost', sans-serif;
        }

        [data-testid="stMarkdownContainer"] p {
            line-height: 1.75;
        }

        [data-testid="stMetric"] {
            background: var(--greter-blush);
            border: 1px solid var(--greter-blush-mid);
            border-radius: 12px;
            padding: 10px;
        }

        [data-testid="stMetricLabel"] {
            color: var(--greter-warm-gray);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            font-weight: 500;
        }

        [data-testid="stMetricValue"] {
            color: var(--greter-garnet-deep);
            font-family: 'Playfair Display', serif;
        }

        .stButton > button {
            background-color: var(--greter-garnet);
            color: var(--greter-cream);
            border: 1px solid var(--greter-garnet-deep);
            border-radius: 10px;
            font-family: 'Jost', sans-serif;
            font-weight: 500;
        }

        .stButton > button:hover {
            border-color: var(--greter-gold);
            color: var(--greter-gold-light);
        }

        button[data-baseweb="tab"] {
            font-family: 'Jost', sans-serif;
            font-weight: 500;
            color: var(--greter-warm-gray);
        }

        button[data-baseweb="tab"][aria-selected="true"] {
            color: var(--greter-garnet);
            border-bottom-color: var(--greter-gold) !important;
        }

        [data-testid="stSidebar"] {
            background-color: var(--greter-blush);
        }
        </style>
        """,
        unsafe_allow_html=True,
    )


def apply_brand_theme() -> None:
    """Apply full app theme (Streamlit + Plotly)."""
    apply_plotly_theme()
    apply_streamlit_theme()

#!/usr/bin/env python3

import os
import sys
from datetime import datetime
from dotenv import load_dotenv

# Load environment variables
load_dotenv(override=True)

# Import the Zernio client
try:
    from src.api.client import ZernioClient, AddonRequiredError, AuthError
except ImportError as e:
    print(f"Error importing Zernio client: {e}")
    sys.exit(1)


def _build_fallback_data(reason: str = ""):
    """Return a safe data payload compatible with all dashboard tabs."""
    now = datetime.now().isoformat()
    if reason:
        print(f"Using fallback data: {reason}")

    return {
        "account_snapshot": {
            "id": "fallback_instagram_account",
            "platform": "instagram",
            "username": "demo_instagram",
            # Keep both keys for backward compatibility across tabs.
            "follower_count": 0,
            "followers_count": 0,
            "posts_count": 0,
            "engagement_rate": 0.0,
            "reach": 0,
            "profile_image": "",
            "updated_at": now,
        },
        "account_health": {
            "id": "fallback_instagram_account",
            "platform": "instagram",
            "status": "unknown",
            "checked_at": now,
            "message": "Datos de fallback cargados",
        },
        "daily_metrics": [],
        "posts": [],
        "comments": [],
        "follower_history": [],
        "best_time_to_post": [],
    }

def load_account_data_from_zernio_with_fallback():
    """Load account data from Zernio API using the official client with fallback to mock data."""

    try:
        # Initialize the Zernio client
        client = ZernioClient()

        # Get account information
        accounts_result = client.list_accounts()
        if not accounts_result or 'accounts' not in accounts_result:
            print("No accounts found")
            return _build_fallback_data("No accounts in API response")

        # Find Instagram account
        instagram_account = None
        for account in accounts_result['accounts']:
            if account['platform'] == 'instagram':
                instagram_account = account
                break

        if not instagram_account:
            print("No Instagram account found")
            return _build_fallback_data("No Instagram account available")

        account_id = instagram_account['_id']

        # Load account health (this is what we use for account snapshot)
        # Use the correct Instagram account insights endpoint
        try:
            health_result = client.get_instagram_account_insights(account_id)
        except AddonRequiredError as e:
            print(f"Addon required for health data: {e}")
            health_result = {}
        except Exception as e:
            print(f"Error getting account health: {e}")
            health_result = {}

        # Load daily analytics (this is what we use for daily metrics)
        try:
            daily_result = client.get_daily_metrics(account_id)
        except AddonRequiredError as e:
            print(f"Addon required for daily analytics: {e}")
            daily_result = {"metrics": []}
        except Exception as e:
            print(f"Error getting daily analytics: {e}")
            daily_result = {"metrics": []}

        # Load follower stats (this is what we use for follower history)
        try:
            follower_result = client.get_follower_stats(account_id)
        except AddonRequiredError as e:
            print(f"Addon required for follower stats: {e}")
            follower_result = {"history": []}
        except Exception as e:
            print(f"Error getting follower stats: {e}")
            follower_result = {"history": []}

        # Load best time to post
        try:
            best_time_result = client.get_best_time_to_post(account_id)
        except AddonRequiredError as e:
            print(f"Addon required for best time data: {e}")
            best_time_result = {"best_time": []}
        except Exception as e:
            print(f"Error getting best time data: {e}")
            best_time_result = {"best_time": []}

        # Load comments (this is what we use for comments)
        try:
            comments_result = client.list_inbox_comments(account_id)
        except AddonRequiredError as e:
            print(f"Addon required for comments: {e}")
            comments_result = {"comments": []}
        except Exception as e:
            print(f"Error getting comments: {e}")
            comments_result = {"comments": []}

        # Load posts (this is what we use for posts)
        try:
            posts_result = client.get_analytics(account_id)
        except AddonRequiredError as e:
            print(f"Addon required for posts: {e}")
            posts_result = {"posts": []}
        except Exception as e:
            print(f"Error getting posts: {e}")
            posts_result = {"posts": []}

        # Prepare the data structure to match what app.py expects
        # Handle case where account insights are not available due to missing add-ons
        if isinstance(health_result, dict) and 'error' in health_result:
            # If we got an error from the API (like addon required), create mock data
            account_health_data = {
                "id": account_id,
                "platform": instagram_account['platform'],
                "status": "unknown",
                "checked_at": datetime.now().isoformat(),
                "message": "Datos de salud no disponibles (requiere Analytics add-on)"
            }
        else:
            # Use actual data from API
            account_health_data = {
                "id": account_id,
                "platform": instagram_account['platform'],
                "status": health_result.get('health_status', 'unknown'),
                "checked_at": datetime.now().isoformat()
            }

        return {
            'account_snapshot': {
                "id": account_id,
                "platform": instagram_account['platform'],
                "username": instagram_account.get('username', ''),
                "follower_count": health_result.get('followers', 0),
                "profile_image": health_result.get('profile_pic_url', ''),
                "updated_at": datetime.now().isoformat()
            },
            'account_health': account_health_data,
            'daily_metrics': daily_result.get('metrics', []),
            'posts': posts_result.get('posts', []),
            'comments': comments_result.get('comments', []),
            'follower_history': follower_result.get('history', []),
            'best_time_to_post': best_time_result.get('best_time', [])
        }

    except AuthError as e:
        print(f"Authentication error: {e}")
        return _build_fallback_data("Authentication error")
    except Exception as e:
        print(f"Error loading data from Zernio: {e}")
        import traceback
        traceback.print_exc()
        return _build_fallback_data("Unhandled exception while loading data")

if __name__ == "__main__":
    # Test the function
    data = load_account_data_from_zernio_with_fallback()
    if data:
        print("Data loaded successfully")
        print(f"Username: {data['account_snapshot']['username']}")
        print(f"Followers: {data['account_snapshot']['follower_count']}")
        print(f"Posts count: {len(data['posts'])}")
        print(f"Comments count: {len(data['comments'])}")
    else:
        print("Failed to load data from Zernio")

